export function createSha256Hash(hash: string): Sha256Hash {
  if (!/^[a-f0-9]{64}$/.test(hash)) {
    throw new Error(`Invalid SHA256 hash format. Expected 64-character hex string, got: ${hash}`);
  }
  return hash as Sha256Hash;
}

