    95→ * Records when changesets were committed or discarded in the model
    96→ */
    97→export interface ChangesetHistoryEntry {
    98→  /** Name of the changeset that was committed or discarded */
    99→  name: string;
   100→  /** ISO 8601 timestamp when the action occurred */
   101→  committed_at: string;
