   235→export function createBackupManifest(data: unknown): BackupManifest {
   236→  if (!data || typeof data !== "object") {
   237→    throw new Error("Backup manifest must be an object");
   238→  }
   239→
   240→  const obj = data as Record<string, unknown>;
   241→
   242→  if (!obj.files || !Array.isArray(obj.files)) {
   243→    throw new Error("Backup manifest must have a files array");
   244→  }
   245→
   246→  if (obj.timestamp && typeof obj.timestamp !== "string") {
   247→    throw new Error("Backup manifest timestamp must be a string if provided");
   248→  }
   249→
   250→  // Validate ISO 8601 timestamp if provided
   251→  let timestamp: string;
   252→  if (obj.timestamp) {
   253→    const timestampDate = new Date(obj.timestamp as string);
   254→    if (isNaN(timestampDate.getTime())) {
   255→      throw new Error(`Invalid timestamp format: ${obj.timestamp}. Expected ISO 8601 string.`);
   256→    }
