   272→    }
   273→
   274→    if (typeof fileObj.checksum !== "string") {
   275→      throw new Error(`Backup manifest file entry ${index} must have a checksum string`);
   276→    }
   277→
   278→    if (typeof fileObj.size !== "number" || fileObj.size < 0) {
   279→      throw new Error(`Backup manifest file entry ${index} must have a non-negative size number`);
   280→    }
   281→
   282→    return {
