/**
 * Changeset application history entry
 * Records when changesets were committed or discarded in the model
 */
export interface ChangesetHistoryEntry {
  /** Name of the changeset that was committed or discarded */
  name: string;
  /** ISO 8601 timestamp when the action occurred */
  committed_at: string;
  /** Type of action performed */
  action: "committed" | "discarded";
}

/**
 * Manifest metadata
 */
export interface ManifestData {
  name: string;
  version: string;
  description?: string;
  author?: string;
  created?: string;
  modified?: string;
  specVersion?: string;
  /** Changeset history for the model */
  changeset_history?: ChangesetHistoryEntry[];
}

/**
 * Model options for customization
 */
export interface ModelOptions {
  enableCache?: boolean;
  lazyLoad?: boolean;
  referenceRegistry?: unknown; // Will be properly typed when implemented
}

/**
 * JSON Schema property definition
 * Represents a single property in a JSON Schema object
 */
export interface JsonSchemaProperty {
  type?: string | string[];
  description?: string;
  enum?: unknown[];
  default?: unknown;
  items?: JsonSchemaProperty;
  properties?: Record<string, JsonSchemaProperty>;
  required?: string[];
  [key: string]: unknown;
}

/**
 * Tool parameter definition for Claude AI tools
 * Describes a single input parameter for a tool
 */
export interface ToolParameter {
  type: string;
  description: string;
  enum?: string[];
  items?: { type: string };
  [key: string]: unknown;
}

