/**
 * VirtualProjectionEngine - Computes merged model views by applying staged changes.
 *
 * Creates virtual (temporary) projections of the base model with staged changes applied,
 * without modifying or persisting the base model. Enables safe preview and validation
 * of changes before commit. Includes projection caching with TTL-based expiration.
 *
 * Staging changes are applied in sequence order to compute accurate merged views.
 */

import type { Model } from "./model.js";
import type { Layer } from "./layer.js";
import type { Element } from "./element.js";
import type { Manifest } from "./manifest.js";
import { Layer as LayerClass } from "./layer.js";
import { Element as ElementClass } from "./element.js";
import type { StagedChange, Change } from "./changeset.js";
import { StagedChangesetStorage } from "./staged-changeset-storage.js";

/**
 * Projected model with isProjection flag to prevent accidental saves.
 * This marker interface ensures that projected models are recognized as temporary
 * and cannot be persisted to disk without explicit commit of the underlying changeset.
 */
export interface ProjectedModel {
  manifest: Manifest;
  layers: Map<string, Layer>;
  isProjection: true; // Always true; marks this as a temporary virtual projection
}

/**
 * Model diff categorizing changeset changes by type.
 * Separates staged changes into additions (new elements), modifications (updated properties),
 * and deletions (removed elements). Used for preview and diff display operations.
 */
export interface ModelDiff {
  additions: Array<{
    elementId: string;
    layerName: string;
    data: Record<string, unknown>; // Complete element state (from change.after)
  }>;
  modifications: Array<{
    elementId: string;
    layerName: string;
    before: Record<string, unknown>; // Previous state (from change.before)
    after: Record<string, unknown>; // New state (from change.after)
  }>;
  deletions: Array<{
    elementId: string;
    layerName: string;

/**
 * Changeset - Represents a collection of model changes.
 *
 * Changesets group related modifications to the architecture model for:
 * - Staging changes before committing to the base model
 * - Audit trail of model changes with before/after snapshots
 * - Collaboration and change tracking across team members
 *
 * Uses the staging workflow (staged/committed/discarded).
 */

/**
 * Migrate legacy status values to new narrowed ChangesetStatus type.
 *
 * Handles migration of legacy status strings from older changeset YAML files:
 * - "draft" → "staged"
 * - "applied" → "committed"
 * - "reverted" → "discarded"
 *
 * Current valid status values pass through unchanged. Non-string values default to "staged".
 * Unrecognized string values are rejected to prevent silent corruption from invalid data.
 *
 * @param status - Status value from changeset storage (may be legacy or new format)
 * @returns Migrated ChangesetStatus value
 * @throws Error if status is an unrecognized string value indicating data corruption
 */
export function migrateChangesetStatus(status: unknown): ChangesetStatus {
  if (typeof status !== "string") {
    return "staged";
  }

  // Map legacy values to new narrowed type
  switch (status) {
    case "draft":
      return "staged";
    case "applied":
      return "committed";
    case "reverted":
      return "discarded";
    case "staged":
    case "committed":
    case "discarded":
      return status as ChangesetStatus;
    default:
      // Reject unrecognized status values — corrupted data should be detected
      throw new Error(
        `Unrecognized changeset status '${status}'. Expected: staged, committed, or discarded. ` +
        `If this is legacy data, ensure it uses one of the supported status values.`
      );
  }
}

/**
 * Represents a single change in a changeset.
 * Records element mutations with before/after snapshots for audit purposes.
 */
export interface Change {
  type: "add" | "update" | "delete";
  elementId: string;
  layerName: string;
  before?: Record<string, unknown>; // Element state before change (for update/delete)
  after?: Record<string, unknown>; // Element state after change (for add/update)
  timestamp?: string; // ISO timestamp; optional in interface but always set before storage
}

/**
 * Represents a staged change with sequence number for ordered replay.
 * Used in the staging workflow to ensure changes are applied in order during commit.
 */
export interface StagedChange extends Change {
  readonly sequenceNumber: number; // 0-based index for ordering during commit replay
}

/**
 * Status values for changesets in the staging workflow.
 *
 * - 'staged': Created and active for staging changes (can accept new changes)
 * - 'committed': Changes have been committed to base model
 * - 'discarded': Changes were discarded without committing
 */

