     1→/**
     2→ * VirtualProjectionEngine - Computes merged model views by applying staged changes.
     3→ *
     4→ * Creates virtual (temporary) projections of the base model with staged changes applied,
     5→ * without modifying or persisting the base model. Enables safe preview and validation
     6→ * of changes before commit. Includes projection caching with TTL-based expiration.
     7→ *
     8→ * Staging changes are applied in sequence order to compute accurate merged views.
     9→ */
    10→
    11→import type { Model } from "./model.js";
    12→import type { Layer } from "./layer.js";
    13→import type { Element } from "./element.js";
    14→import type { Manifest } from "./manifest.js";
    15→import { Layer as LayerClass } from "./layer.js";
    16→import { Element as ElementClass } from "./element.js";
    17→import type { StagedChange, Change } from "./changeset.js";
    18→import { StagedChangesetStorage } from "./staged-changeset-storage.js";
    19→
    20→/**
    21→ * Projected model with isProjection flag to prevent accidental saves.
    22→ * This marker interface ensures that projected models are recognized as temporary
    23→ * and cannot be persisted to disk without explicit commit of the underlying changeset.
    24→ */
    25→export interface ProjectedModel {
    26→  manifest: Manifest;
    27→  layers: Map<string, Layer>;
    28→  isProjection: true; // Always true; marks this as a temporary virtual projection
    29→}
    30→
    31→/**
    32→ * Model diff categorizing changeset changes by type.
    33→ * Separates staged changes into additions (new elements), modifications (updated properties),
    34→ * and deletions (removed elements). Used for preview and diff display operations.
    35→ */
    36→export interface ModelDiff {
    37→  additions: Array<{
    38→    elementId: string;
    39→    layerName: string;
    40→    data: Record<string, unknown>; // Complete element state (from change.after)
    41→  }>;
    42→  modifications: Array<{
    43→    elementId: string;
    44→    layerName: string;
    45→    before: Record<string, unknown>; // Previous state (from change.before)
    46→    after: Record<string, unknown>; // New state (from change.after)
    47→  }>;
    48→  deletions: Array<{
    49→    elementId: string;
    50→    layerName: string;
    51→    data: Record<string, unknown>; // Element state before deletion (from change.before)
    52→  }>;
    53→}
    54→
    55→/**
    56→ * Single cached layer projection.
    57→ * Stores the computed projected layer and timestamp for cache expiration.
    58→ */
    59→interface CacheEntry {
    60→  layer: Layer;
    61→  computedAt: string; // ISO timestamp for age calculation
    62→}
    63→
    64→/**
    65→ * Cache hit/miss metrics for monitoring cache performance.
    66→ * Tracks successful cache hits, misses, and invalidations per changeset.
    67→ */
    68→interface CacheMetrics {
    69→  hits: number; // Number of successful cache hits
    70→  misses: number; // Number of cache misses (required computation)
    71→  invalidations: number; // Number of invalidation operations
    72→  lastInvalidation?: string; // ISO timestamp of last invalidation
    73→}
    74→
    75→/**
    76→ * Projection cache for storing computed layer projections.
    77→ * Uses TTL-based expiration to prevent stale projections.
    78→ * Entries are lazily removed when expired on access or during periodic cleanup.
    79→ */
    80→interface ProjectionCache {
    81→  cache: Map<string, CacheEntry>; // Key format: `${changesetId}:${layerName}`
    82→  metrics: Map<string, CacheMetrics>; // Cache metrics keyed by changesetId
    83→  maxAge: number; // Cache entry TTL in milliseconds (5 minutes default)
    84→  lastCleanup: number; // Timestamp of last cleanup to limit cleanup frequency
    85→}
    86→
    87→/**
    88→ * VirtualProjectionEngine - Computes merged model views without persisting.
    89→ * Applies staged changes to a cloned base model to compute projections.
    90→ * Uses caching with TTL-based expiration to optimize repeated projections.
    91→ */
    92→export class VirtualProjectionEngine {
    93→  private stagingAreaManager: StagedChangesetStorage;
    94→  private projectionCache: ProjectionCache;
    95→
    96→  /**
    97→   * Create a new projection engine.
    98→   *
    99→   * @param rootPath - Root path to the model (used by StagedChangesetStorage)
   100→   */
   101→  constructor(rootPath: string) {
   102→    this.stagingAreaManager = new StagedChangesetStorage(rootPath);
   103→    this.projectionCache = {
   104→      cache: new Map(),
   105→      metrics: new Map(),
   106→      maxAge: 5 * 60 * 1000, // 5-minute TTL for cached projections
   107→      lastCleanup: Date.now(),
   108→    };
   109→  }
   110→
   111→  /**
   112→   * Project a single element by applying staged changes to it.
   113→   * Merges the element's base state with staged changes to compute its projected state.
   114→   *
   115→   * @param baseModel - The base model to project from
   116→   * @param changesetId - ID of the changeset containing staged changes
   117→   * @param elementId - ID of the element to project
   118→   * @returns Projected element with staged changes applied, or null if element is deleted
   119→   * @throws Error if changeset not found
   120→   *
   121→   * @remarks
   122→   * If multiple changes exist for the element, the last change determines final state.
   123→   * For 'delete' operations, returns null.
   124→   * For 'add' operations without base element, creates new element from staged data.
   125→   * For 'update' operations, merges staged changes with base element properties.
   126→   */
   127→  async projectElement(
   128→    baseModel: Model,
   129→    changesetId: string,
   130→    elementId: string
   131→  ): Promise<Element | null> {
   132→    const changeset = await this.stagingAreaManager.load(changesetId);
   133→    if (!changeset) {
   134→      throw new Error(`Changeset '${changesetId}' not found`);
   135→    }
   136→
   137→    // Find all changes for this element across all layers
   138→    const elementChanges = changeset.changes.filter(
   139→      (c: Change) => c.elementId === elementId
   140→    ) as StagedChange[];
   141→
   142→    if (elementChanges.length === 0) {
   143→      // No changes, return base element if it exists
   144→      return baseModel.getElementById(elementId) || null;
   145→    }
   146→
   147→    // Get the last change to determine the element's final state
   148→    const lastChange = elementChanges[elementChanges.length - 1];
   149→
   150→    if (lastChange.type === "delete") {
   151→      return null;
   152→    }
   153→
   154→    // For add or update, construct the projected element
   155→    const baseElement = baseModel.getElementById(elementId);
   156→    const projectedData = lastChange.after || {};
   157→
   158→    if (baseElement) {
   159→      // Create a new element with projected data merged with base
   160→      // Handle both 'attributes' (spec-aligned) and 'properties' (legacy) field names
   161→      const projectedAttributes =
   162→        typeof projectedData.attributes === "object"
   163→          ? projectedData.attributes
   164→          : typeof projectedData.properties === "object"
   165→            ? projectedData.properties
   166→            : {};
   167→
   168→      const mergedData = {
   169→        id: baseElement.id,
   170→        spec_node_id: baseElement.spec_node_id,
   171→        type: typeof projectedData.type === "string" ? projectedData.type : baseElement.type,
   172→        layer_id: baseElement.layer_id,
   173→        name: typeof projectedData.name === "string" ? projectedData.name : baseElement.name,
   174→        description:
   175→          typeof projectedData.description === "string"
   176→            ? projectedData.description
   177→            : baseElement.description,
   178→        attributes: {
   179→          ...baseElement.attributes,
   180→          ...projectedAttributes,
   181→        },
   182→        references: Array.isArray(projectedData.references)
   183→          ? projectedData.references
   184→          : baseElement.references,
   185→        relationships: Array.isArray(projectedData.relationships)
   186→          ? projectedData.relationships
   187→          : baseElement.relationships,
   188→        source_reference: baseElement.source_reference,
   189→        metadata: baseElement.metadata,
   190→      };
   191→
   192→      return new ElementClass(mergedData);
   193→    } else if (lastChange.type === "add") {
   194→      // New element being added
   195→      return new ElementClass({
   196→        id: elementId,
   197→        spec_node_id: lastChange.after?.spec_node_id || "",
   198→        type: (projectedData.type as string) || "unknown",
   199→        layer_id: lastChange.layerName,
   200→        name: (projectedData.name as string) || elementId,
   201→        description: (projectedData.description as string) || "",
   202→        attributes: (typeof projectedData.attributes === "object"
   203→          ? projectedData.attributes
   204→          : {}) as Record<string, unknown>,
   205→        references: Array.isArray(projectedData.references) ? projectedData.references : [],
   206→        relationships: Array.isArray(projectedData.relationships)
   207→          ? projectedData.relationships
   208→          : [],
   209→        layer: lastChange.layerName,
   210→      });
   211→    }
   212→
   213→    return null;
   214→  }
   215→
   216→  /**
   217→   * Project a layer by applying staged changes to a clone of the base layer.
   218→   * Checks cache first; computes and caches result if not found or expired.
   219→   *
   220→   * @param baseModel - The base model to project from
   221→   * @param changesetId - ID of the changeset containing staged changes
   222→   * @param layerName - Name of the layer to project
   223→   * @returns Projected layer with staged changes applied
   224→   * @throws Error if changeset or base layer not found
   225→   *
   226→   * @remarks
   227→   * Computation process:
   228→   * 1. Check projection cache (returns if found and not expired)
   229→   * 2. Clone base layer to avoid mutations
   230→   * 3. Load staged changes filtered to this layer
   231→   * 4. Apply changes in sequence number order (add/update/delete)
   232→   * 5. Cache result with timestamp for TTL tracking
   233→   * 6. Trigger periodic cache cleanup
   234→   */
   235→  async projectLayer(baseModel: Model, changesetId: string, layerName: string): Promise<Layer> {
   236→    // Check cache first
   237→    const cacheKey = `${changesetId}:${layerName}`;
   238→    const cached = this.projectionCache.cache.get(cacheKey);
   239→
   240→    if (cached) {
   241→      const age = Date.now() - new Date(cached.computedAt).getTime();
   242→      if (age < this.projectionCache.maxAge) {
   243→        // Record cache hit
   244→        this.recordCacheHit(changesetId);
   245→        return cached.layer;
   246→      } else {
   247→        // Invalidate expired entry
   248→        this.projectionCache.cache.delete(cacheKey);
   249→      }
   250→    }
   251→
   252→    // Record cache miss
   253→    this.recordCacheMiss(changesetId);
   254→
   255→    // Load base layer
   256→    const baseLayer = await baseModel.getLayer(layerName);
   257→    if (!baseLayer) {
   258→      throw new Error(`Layer '${layerName}' not found in base model`);
   259→    }
   260→
   261→    // Clone base layer to avoid mutations
   262→    const projectedLayer = this.cloneLayer(baseLayer);
   263→
   264→    // Load staged changes for this layer
   265→    const changeset = await this.stagingAreaManager.load(changesetId);
   266→    if (!changeset) {
   267→      throw new Error(`Changeset '${changesetId}' not found`);
   268→    }
   269→
   270→    const layerChanges = (changeset.changes as StagedChange[])
   271→      .filter((c: StagedChange) => c.layerName === layerName)
   272→      .sort((a: StagedChange, b: StagedChange) => a.sequenceNumber - b.sequenceNumber);
   273→
   274→    // Apply changes in sequence order
   275→    for (const change of layerChanges) {
   276→      switch (change.type) {
   277→        case "add":
   278→          if (change.after) {
   279→            const newElement = new ElementClass({
   280→              id: change.elementId,
   281→              spec_node_id: change.after.spec_node_id || "",
   282→              type: (change.after.type as string) || "unknown",
   283→              layer_id: layerName,
   284→              name: (change.after.name as string) || change.elementId,
   285→              description: (change.after.description as string) || "",
   286→              attributes: (typeof change.after.attributes === "object"
   287→                ? change.after.attributes
   288→                : {}) as Record<string, unknown>,
   289→              references: Array.isArray(change.after.references) ? change.after.references : [],
   290→              relationships: Array.isArray(change.after.relationships)
   291→                ? change.after.relationships
   292→                : [],
   293→              layer: layerName,
   294→            });
   295→            projectedLayer.addElement(newElement);
   296→          }
   297→          break;
   298→
   299→        case "update":
   300→          if (change.after) {
   301→            // Get the existing element to preserve all state
   302→            const existing = projectedLayer.getElement(change.elementId);
   303→            if (existing) {
   304→              // Create updated element with merged attributes
   305→              // Handle both 'attributes' (spec-aligned) and 'properties' (legacy) field names
   306→              const afterAttributes =
   307→                typeof change.after.attributes === "object"
   308→                  ? change.after.attributes
   309→                  : typeof change.after.properties === "object"
   310→                    ? change.after.properties
   311→                    : {};
   312→
   313→              const mergedAttributes: Record<string, unknown> = {
   314→                ...existing.attributes,
   315→                ...afterAttributes,
   316→              };
   317→
   318→              const updatedElement = new ElementClass({
   319→                id: existing.id,
   320→                spec_node_id: existing.spec_node_id,
   321→                layer_id: existing.layer_id,
   322→                type: typeof change.after.type === "string" ? change.after.type : existing.type,
   323→                name: typeof change.after.name === "string" ? change.after.name : existing.name,
   324→                description:
   325→                  typeof change.after.description === "string"
   326→                    ? change.after.description
   327→                    : existing.description,
   328→                attributes: mergedAttributes,
   329→                references: Array.isArray(change.after.references)
   330→                  ? change.after.references
   331→                  : existing.references,
   332→                relationships: Array.isArray(change.after.relationships)
   333→                  ? change.after.relationships
   334→                  : existing.relationships,
   335→                layer: layerName,
   336→                source_reference: existing.source_reference,
   337→                metadata: existing.metadata,
   338→              });
   339→
   340→              projectedLayer.updateElement(updatedElement);
   341→            }
   342→          }
   343→          break;
   344→
   345→        case "delete":
   346→          const existingForDelete = projectedLayer.getElement(change.elementId);
   347→          if (existingForDelete) {
   348→            projectedLayer.deleteElement(existingForDelete.id);
   349→          }
   350→          break;
   351→      }
   352→    }
   353→
   354→    // Cache the result
   355→    const cacheEntry: CacheEntry = {
   356→      layer: projectedLayer,
   357→      computedAt: new Date().toISOString(),
   358→    };
   359→    this.projectionCache.cache.set(cacheKey, cacheEntry);
   360→
   361→    // Periodic cleanup of expired entries
   362→    this.cleanupExpiredCache();
   363→
   364→    return projectedLayer;
   365→  }
   366→
   367→  /**
   368→   * Project entire model by applying staged changes to all layers.
   369→   * Creates a complete projected model view that includes both changed and unchanged layers.
   370→   *
   371→   * @param baseModel - The base model to project from
   372→   * @param changesetId - ID of the changeset containing staged changes
   373→   * @returns ProjectedModel with isProjection=true flag (prevents accidental saves)
   374→   * @throws Error if changeset not found
   375→   *
   376→   * @remarks
   377→   * Projection includes:
   378→   * - All layers mentioned in changeset changes
   379→   * - All layers from base model (to have complete model state)
   380→   * - Base model's manifest (unchanged)
   381→   * Returned model has isProjection=true to prevent accidental persistence.
   382→   */
   383→  async projectModel(baseModel: Model, changesetId: string): Promise<ProjectedModel> {
   384→    const changeset = await this.stagingAreaManager.load(changesetId);
   385→    if (!changeset) {
   386→      throw new Error(`Changeset '${changesetId}' not found`);
   387→    }
   388→
   389→    const projectedLayers = new Map<string, Layer>();
   390→
   391→    // Project all layers mentioned in the changeset
   392→    const layerNames = new Set<string>();
   393→    for (const change of changeset.changes) {
   394→      layerNames.add(change.layerName);
   395→    }
   396→
   397→    // Also include all base layers to get complete model
   398→    for (const baseLayerName of baseModel.getLayerNames()) {
   399→      layerNames.add(baseLayerName);
   400→    }
   401→
   402→    // Project each layer
   403→    for (const layerName of layerNames) {
   404→      const projectedLayer = await this.projectLayer(baseModel, changesetId, layerName);
   405→      projectedLayers.set(layerName, projectedLayer);
   406→    }
   407→
   408→    // Create projected model with isProjection flag
   409→    const projectedModel: ProjectedModel = {
   410→      manifest: baseModel.manifest,
   411→      layers: projectedLayers,
   412→      isProjection: true,
   413→    };
   414→
   415→    return projectedModel;
   416→  }
   417→
   418→  /**
   419→   * Compute diff by categorizing changeset changes by type.
   420→   * Extracts the staged changes and organizes them into additions, modifications, and deletions.
   421→   *
   422→   * @param _baseModel - The base model (unused; included for interface compatibility)
   423→   * @param changesetId - ID of the changeset to compute diff for
   424→   * @returns ModelDiff with changes categorized by type
   425→   * @throws Error if changeset not found
   426→   *
   427→   * @remarks
   428→   * Diff is computed directly from changeset changes; does not perform deep comparison.
   429→   * Each change's before/after snapshots are included for detailed display.
   430→   */
   431→  async computeDiff(_baseModel: Model, changesetId: string): Promise<ModelDiff> {
   432→    const changeset = await this.stagingAreaManager.load(changesetId);
   433→    if (!changeset) {
   434→      throw new Error(`Changeset '${changesetId}' not found`);
   435→    }
   436→
   437→    const changes = changeset.changes as StagedChange[];
   438→
   439→    return {
   440→      additions: changes
   441→        .filter((c: StagedChange) => c.type === "add")
   442→        .map((c: StagedChange) => ({
   443→          elementId: c.elementId,
   444→          layerName: c.layerName,
   445→          data: c.after || {},
   446→        })),
   447→
   448→      modifications: changes
   449→        .filter((c: StagedChange) => c.type === "update")
   450→        .map((c: StagedChange) => ({
   451→          elementId: c.elementId,
   452→          layerName: c.layerName,
   453→          before: c.before || {},
   454→          after: c.after || {},
   455→        })),
   456→
   457→      deletions: changes
   458→        .filter((c: StagedChange) => c.type === "delete")
   459→        .map((c: StagedChange) => ({
   460→          elementId: c.elementId,
   461→          layerName: c.layerName,
   462→          data: c.before || {},
   463→        })),
   464→    };
   465→  }
   466→
   467→  /**
   468→   * Get affected layers for an element in a changeset.
   469→   * Returns all layers that have cached projections and contain changes for the element.
   470→   *
   471→   * @param changesetId - ID of the changeset
   472→   * @param elementId - ID of the element being unstaged
   473→   * @returns Set of affected layer names
   474→   *
   475→   * @remarks
   476→   * When unstaging an element, only the layers where that element was modified
   477→   * need cache invalidation. This enables granular invalidation instead of
   478→   * invalidating the entire changeset cache.
   479→   */
   480→  private async getAffectedLayers(changesetId: string, elementId: string): Promise<Set<string>> {
   481→    const affectedLayers = new Set<string>();
   482→
   483→    try {
   484→      const changeset = await this.stagingAreaManager.load(changesetId);
   485→      if (!changeset) {
   486→        return affectedLayers;
   487→      }
   488→
   489→      // Find all layers that have changes for this element
   490→      for (const change of changeset.changes) {
   491→        if (change.elementId === elementId) {
   492→          affectedLayers.add(change.layerName);
   493→        }
   494→      }
   495→    } catch {
   496→      // If changeset can't be loaded, return empty set (no invalidation needed)
   497→      // This handles the case where changeset is deleted or corrupted
   498→    }
   499→
   500→    return affectedLayers;
   501→  }
   502→
   503→  /**
   504→   * Record a cache hit for metrics tracking.
   505→   *
   506→   * @param changesetId - ID of the changeset
   507→   */
   508→  private recordCacheHit(changesetId: string): void {
   509→    const metrics = this.projectionCache.metrics.get(changesetId) || {
   510→      hits: 0,
   511→      misses: 0,
   512→      invalidations: 0,
   513→    };
   514→    metrics.hits++;
   515→    this.projectionCache.metrics.set(changesetId, metrics);
   516→  }
   517→
   518→  /**
   519→   * Record a cache miss for metrics tracking.
   520→   *
   521→   * @param changesetId - ID of the changeset
   522→   */
   523→  private recordCacheMiss(changesetId: string): void {
   524→    const metrics = this.projectionCache.metrics.get(changesetId) || {
   525→      hits: 0,
   526→      misses: 0,
   527→      invalidations: 0,
   528→    };
   529→    metrics.misses++;
   530→    this.projectionCache.metrics.set(changesetId, metrics);
   531→  }
   532→
   533→  /**
   534→   * Record a cache invalidation for metrics tracking.
   535→   *
   536→   * @param changesetId - ID of the changeset
   537→   */
   538→  private recordInvalidation(changesetId: string): void {
   539→    const metrics = this.projectionCache.metrics.get(changesetId) || {
   540→      hits: 0,
   541→      misses: 0,
   542→      invalidations: 0,
   543→    };
   544→    metrics.invalidations++;
   545→    metrics.lastInvalidation = new Date().toISOString();
   546→    this.projectionCache.metrics.set(changesetId, metrics);
   547→  }
   548→
   549→  /**
   550→   * Get cache metrics for a changeset (for monitoring and debugging).
   551→   *
   552→   * @param changesetId - ID of the changeset
   553→   * @returns Cache metrics or undefined if no metrics exist
   554→   */
   555→  getCacheMetrics(changesetId: string): CacheMetrics | undefined {
   556→    return this.projectionCache.metrics.get(changesetId);
   557→  }
   558→
   559→  /**
   560→   * Invalidate projection cache when changes are staged.
   561→   * Removes cached projections to ensure fresh computation next time.
   562→   *
   563→   * @param changesetId - ID of the changeset being modified
   564→   * @param layerName - Optional: specific layer to invalidate (all if omitted)
   565→   *
   566→   * @remarks
   567→   * If layerName is provided, only that layer's projection is invalidated.
   568→   * Otherwise, all projections for the changeset are invalidated.
   569→   */
   570→  invalidateOnStage(changesetId: string, layerName?: string): void {
   571→    if (layerName) {
   572→      // Invalidate specific layer projection
   573→      const cacheKey = `${changesetId}:${layerName}`;
   574→      this.projectionCache.cache.delete(cacheKey);
   575→      this.recordInvalidation(changesetId);
   576→    } else {
   577→      // Invalidate all projections for this changeset
   578→      for (const key of this.projectionCache.cache.keys()) {
   579→        if (key.startsWith(`${changesetId}:`)) {
   580→          this.projectionCache.cache.delete(key);
   581→        }
   582→      }
   583→      this.recordInvalidation(changesetId);
   584→    }
   585→  }
   586→
   587→  /**
   588→   * Invalidate projection cache when changes are unstaged.
   589→   * Uses layer-specific invalidation for the affected element's layers.
   590→   *
   591→   * @param changesetId - ID of the changeset being modified
   592→   * @param elementId - Optional: ID of element being unstaged (enables granular invalidation)
   593→   *
   594→   * @remarks
   595→   * If elementId is provided, only the layers containing that element are invalidated.
   596→   * This is more efficient than invalidating the entire changeset cache when
   597→   * unstaging elements from a multi-layer changeset.
   598→   * If elementId is omitted, invalidates all projections for the changeset.
   599→   */
   600→  async invalidateOnUnstage(changesetId: string, elementId?: string): Promise<void> {
   601→    if (elementId) {
   602→      // Layer-specific invalidation: only invalidate affected layers
   603→      const affectedLayers = await this.getAffectedLayers(changesetId, elementId);
   604→      for (const layerName of affectedLayers) {
   605→        const cacheKey = `${changesetId}:${layerName}`;
   606→        this.projectionCache.cache.delete(cacheKey);
   607→      }
   608→      if (affectedLayers.size > 0) {
   609→        this.recordInvalidation(changesetId);
   610→      }
   611→    } else {
   612→      // Full invalidation: clear all projections for this changeset
   613→      for (const key of this.projectionCache.cache.keys()) {
   614→        if (key.startsWith(`${changesetId}:`)) {
   615→          this.projectionCache.cache.delete(key);
   616→        }
   617→      }
   618→      this.recordInvalidation(changesetId);
   619→    }
   620→  }
   621→
   622→  /**
   623→   * Invalidate all projections for a changeset when it's discarded.
   624→   * Clears all cached projections for this changeset to free memory.
   625→   *
   626→   * @param changesetId - ID of the changeset being discarded
   627→   */
   628→  invalidateOnDiscard(changesetId: string): void {
   629→    for (const key of this.projectionCache.cache.keys()) {
   630→      if (key.startsWith(`${changesetId}:`)) {
   631→        this.projectionCache.cache.delete(key);
   632→      }
   633→    }
   634→  }
   635→
   636→  /**
   637→   * Clone a layer to create an independent copy.
   638→   * Shallow clones all elements and metadata to avoid mutations.
   639→   * Cloned layer is marked clean to prevent unintended saves.
   640→   *
   641→   * @param layer - The layer to clone
   642→   * @returns New layer with cloned elements and metadata
   643→   *
   644→   * @remarks
   645→   * Cloning strategy:
   646→   * 1. Create new Layer with same name
   647→   * 2. Clone each element: shallow copy properties object and array references
   648→   * 3. Copy layer metadata if present
   649→   * 4. Mark cloned layer as clean to prevent automatic saves
   650→   * This ensures changes to projection don't affect base layer.
   651→   * Note: Shallow cloning is sufficient since properties are read-only in projections.
   652→   */
   653→  private cloneLayer(layer: Layer): Layer {
   654→    const cloned = new LayerClass(layer.name);
   655→
   656→    // Clone all elements (shallow copy - read-only in projection)
   657→    for (const element of layer.listElements()) {
   658→      const elementClone = new ElementClass({
   659→        id: element.id,
   660→        spec_node_id: element.spec_node_id,
   661→        type: element.type,
   662→        layer_id: element.layer_id,
   663→        name: element.name,
   664→        description: element.description,
   665→        attributes: { ...element.attributes }, // Shallow copy (attributes are read-only in projection)
   666→        references: [...(element.references || [])], // Shallow copy of array
   667→        relationships: [...(element.relationships || [])], // Shallow copy of array
   668→        layer: element.layer,
   669→        source_reference: element.source_reference,
   670→        metadata: element.metadata,
   671→      });
   672→      cloned.addElement(elementClone);
   673→    }
   674→
   675→    // Preserve layer metadata if present
   676→    if (layer.metadata) {
   677→      cloned.metadata = { ...layer.metadata };
   678→    }
   679→
   680→    // Mark as clean to prevent projection from being saved
   681→    cloned.markClean();
   682→    return cloned;
   683→  }
   684→
   685→  /**
   686→   * Clean up expired cache entries periodically (every 60 seconds).
   687→   * Removes entries that exceed the maxAge TTL.
   688→   * Runs at most once per minute to limit overhead.
   689→   *
   690→   * @remarks
   691→   * Cleanup is triggered after each projection computation.
   692→   * Early exit if last cleanup was less than 60 seconds ago.
   693→   * Entries are marked for deletion based on age calculation from computedAt timestamp.
   694→   */
   695→  private cleanupExpiredCache(): void {
   696→    const now = Date.now();
   697→
   698→    // Limit cleanup frequency to at most every 60 seconds
   699→    if (now - this.projectionCache.lastCleanup < 60 * 1000) {
   700→      return;
   701→    }
   702→
   703→    // Remove entries that have exceeded their TTL
   704→    for (const [key, entry] of this.projectionCache.cache.entries()) {
   705→      const age = now - new Date(entry.computedAt).getTime();
   706→      if (age >= this.projectionCache.maxAge) {
   707→        this.projectionCache.cache.delete(key);
   708→      }
   709→    }
   710→
   711→    this.projectionCache.lastCleanup = now;
   712→  }
   713→}
