    });
  });

  describe("element subcommands", () => {
    // Model is already initialized in the global beforeEach hook

    it("should add element via element subcommand", async () => {
      const result = await runDr(
        "element",
        "add",
        "motivation",
        "goal",
        "test-goal",
        "--name",
