  describe("relationship subcommands", () => {
    beforeEach(async () => {
      // Model is already initialized; add test data
      await runDr("add", "motivation", "goal", "Goal 1");
      await runDr("add", "motivation", "goal", "Goal 2");
      await runDr("add", "motivation", "goal", "Goal 3");
