     1→/**
     2→ * Golden Copy Test Helper
     3→ *
     4→ * Provides the core interface for tests to use the shared golden copy cache.
     5→ * This is the spec-aligned implementation that all tests should use.
     6→ *
     7→ * Architecture:
     8→ * - Single golden copy created once per test suite at suite initialization
     9→ * - Stored in a temporary location (`/tmp/dr-golden-*`)
    10→ * - Each test receives a unique working directory cloned from the golden copy
    11→ * - Thread-safe: Multiple test workers can clone from the same golden copy
    12→ * - Cleanup occurs at test suite shutdown via cleanupGoldenCopy()
    13→ */
    14→
    15→import { mkdir, cp, rm, access } from "fs/promises";
    16→import { tmpdir } from "os";
    17→import { join, resolve } from "path";
    18→import { cwd } from "process";
    19→
    20→let goldenCopyPath: string | null = null;
    21→let initializationPromise: Promise<string> | null = null;
    22→let initializationError: Error | null = null;
    23→
    24→/**
    25→ * Initialize the shared golden copy of the baseline test project.
    26→ * This is called once per test suite execution.
    27→ * Thread-safe: subsequent calls return the same path.
    28→ *
    29→ * Architecture:
    30→ * - Creates a single copy of the baseline project in a temporary location
    31→ * - All test working directories are subsequently cloned from this golden copy
    32→ * - The golden copy itself is read-only after initialization
    33→ * - Initialized on first call or when accessed via createTestWorkdir()
    34→ *
    35→ * Usage:
    36→ * ```typescript
    37→ * beforeAll(async () => {
    38→ *   const goldenPath = await initGoldenCopy();
    39→ *   console.log(`Golden copy at: ${goldenPath}`);
    40→ * });
    41→ * ```
    42→ *
    43→ * @returns Promise<string> Path to the golden copy directory
    44→ */
    45→export async function initGoldenCopy(): Promise<string> {
    46→  // Return cached path if already initialized
    47→  if (goldenCopyPath) return goldenCopyPath;
    48→
    49→  // If there was a previous error, throw it again
    50→  if (initializationError) {
    51→    throw initializationError;
    52→  }
    53→
    54→  // If initialization is in progress, wait for it to complete
    55→  if (initializationPromise) return initializationPromise;
    56→
    57→  // Create a new initialization promise and cache it to prevent concurrent initialization
    58→  initializationPromise = (async () => {
    59→    // Resolve baseline path - try both possible locations
    60→    let BASELINE = resolve("/workspace", "cli-validation/test-project/baseline");
    61→
    62→    // Fallback: try relative to current working directory
    63→    try {
    64→      await access(BASELINE);
    65→    } catch {
    66→      const projectRoot = resolve(cwd(), "..");
    67→      BASELINE = resolve(projectRoot, "cli-validation/test-project/baseline");
    68→    }
    69→
    70→    goldenCopyPath = join(
    71→      tmpdir(),
    72→      `dr-golden-${Date.now()}-${Math.random().toString(36).substring(2, 9)}`
    73→    );
    74→
    75→    try {
    76→      await mkdir(goldenCopyPath, { recursive: true });
    77→      await cp(BASELINE, goldenCopyPath, { recursive: true });
    78→
    79→      // Verify filesystem operations are committed by checking key files
    80→      await verifyFilesystemReady(goldenCopyPath);
    81→
    82→      if (process.env.DEBUG_GOLDEN_COPY) {
    83→        console.log(`Golden copy initialized at: ${goldenCopyPath}`);
    84→      }
    85→    } catch (error) {
    86→      goldenCopyPath = null;
    87→      initializationPromise = null;
    88→      const err = new Error(
    89→        `Failed to initialize golden copy: ${error instanceof Error ? error.message : String(error)}`
    90→      );
    91→      initializationError = err;
    92→      throw err;
    93→    }
    94→
    95→    return goldenCopyPath!;
    96→  })();
    97→
    98→  return initializationPromise;
    99→}
   100→
   101→/**
   102→ * Create an isolated test working directory from the golden copy.
   103→ * Each test receives a unique directory pre-populated with baseline data.
   104→ *
   105→ * This is the primary function tests use for setup.
   106→ *
   107→ * Architecture:
   108→ * - Ensures golden copy is initialized on first call
   109→ * - Creates a unique temporary directory for each test
   110→ * - Copies entire golden copy to the test directory
   111→ * - Returns cleanup function to remove the test directory
   112→ * - Test directory is independent and can be safely modified
   113→ *
   114→ * Usage:
   115→ * ```typescript
   116→ * let testDir: string;
   117→ * let cleanup: () => Promise<void>;
   118→ *
   119→ * beforeEach(async () => {
   120→ *   const workdir = await createTestWorkdir();
   121→ *   testDir = workdir.path;
   122→ *   cleanup = workdir.cleanup;
   123→ * });
   124→ *
   125→ * afterEach(async () => {
   126→ *   await cleanup();
   127→ * });
   128→ *
   129→ * test("validates model", async () => {
   130→ *   const result = await runDr(['validate'], { cwd: testDir });
   131→ *   expect(result.exitCode).toBe(0);
   132→ * });
   133→ * ```
   134→ *
   135→ * @returns Promise resolving to { path: string, cleanup: () => Promise<void> }
   136→ */
   137→export async function createTestWorkdir(): Promise<{
   138→  path: string;
   139→  cleanup: () => Promise<void>;
   140→}> {
   141→  const golden = await initGoldenCopy();
   142→
   143→  const testId = `${Date.now()}-${Math.random().toString(36).substring(2, 9)}`;
   144→  const testDir = join(tmpdir(), `dr-test-${testId}`);
   145→
   146→  let copyAttempts = 0;
   147→  const maxCopyAttempts = 3;
   148→  let lastCopyError: Error | null = null;
   149→
   150→  try {
   151→    // Attempt to copy with retries for race conditions
   152→    for (copyAttempts = 0; copyAttempts < maxCopyAttempts; copyAttempts++) {
   153→      try {
   154→        await mkdir(testDir, { recursive: true });
   155→        // Copy golden copy to test directory with timeout
   156→        await Promise.race([
   157→          cp(golden, testDir, { recursive: true }),
   158→          new Promise((_, reject) =>
   159→            setTimeout(() => reject(new Error("Copy operation timed out after 30s")), 30000)
   160→          ),
   161→        ]);
   162→
   163→        // After copy, add explicit sync to ensure all filesystem operations are flushed
   164→        // This is a workaround for concurrent test execution race conditions
   165→        if (process.platform !== "win32") {
   166→          try {
   167→            // Try to access a key file to force filesystem sync
   168→            const { spawnSync } = await import("child_process");
   169→            spawnSync("sync", [], { stdio: "ignore" });
   170→          } catch {
   171→            // Ignore sync errors on systems that don't support it
   172→          }
   173→        }
   174→
